 51→template<typename T>
 52→concept XLenT =
 53→  std::is_same_v<T, std::uint32_t> || std::is_same_v<T, std::uint64_t>;
 54→
 55→template<XLenT xlen_t>
 56→void read_elf_into_memory(const LIEF::ELF::Binary& elf,
 57→                          const xlen_t base_addr,
 58→                          const std::span<uint8_t> buf)
 59→{
 60→  namespace ELF = LIEF::ELF;
 61→
 62→  assert(buf.size() < std::numeric_limits<xlen_t>::max() - base_addr);
 63→
 64→  if (std::is_same_v<xlen_t, uint32_t>
 65→      && elf.type() != ELF::ELF_CLASS::ELFCLASS32) [[unlikely]]
 66→    throw std::runtime_error("Executable is not of ELFCLASS32");
 67→  else if (std::is_same_v<xlen_t, uint64_t>
 68→           && elf.type() != ELF::ELF_CLASS::ELFCLASS64) [[unlikely]]
 69→    throw std::runtime_error("Executable is not of ELFCLASS64");
 70→
 71→  if (elf.header().identity_data() != ELF::ELF_DATA::ELFDATA2LSB) [[unlikely]]
 72→    throw std::runtime_error("Only little-endian executables are supported");
 73→
 74→  if (elf.header().machine_type() != ELF::ARCH::EM_RISCV) [[unlikely]]
 75→    throw std::runtime_error("Not EM_RISCV");
 76→
 77→  for (const auto& seg: elf.segments()) {
 78→    if (seg.type() != ELF::SEGMENT_TYPES::PT_LOAD)
 79→      continue;
 80→
 81→    const auto paddr = boost::numeric_cast<xlen_t>(seg.physical_address());
 82→    const auto memsz = boost::numeric_cast<xlen_t>(seg.virtual_size());
 83→    const auto filesz = boost::numeric_cast<xlen_t>(seg.physical_size());
 84→    spdlog::info("loading segment: addr={:#x}, memsz={}, filesz={}", paddr,
 85→                 memsz, filesz);
 86→
 87→    if (memsz > std::numeric_limits<xlen_t>::max() - paddr)
 88→      throw std::runtime_error("PT_LOAD address overflow");
 89→    if (paddr < base_addr || paddr + memsz >= base_addr + buf.size())
 90→      throw std::runtime_error("PT_LOAD is not contained within memory region");
 91→
 92→    const auto offset = paddr - base_addr;
 93→    std::copy_n(seg.content().begin(), filesz, buf.subspan(offset).begin());
 94→    if (memsz > filesz)
 95→      std::fill_n(buf.subspan(offset + filesz).begin(), memsz - filesz, 0);
 96→  }
 97→}
